"use client"

import * as React from "react"
import {
  Card,
  CardContent,
  CardHeader,
  CardTitle,
  CardDescription,
  Statistic,
  PersonCell,
  Badge,
  Button,
  Separator,
  Meter,
  Tag,
  Select,
  EmptyState,
  Tooltip,
  TooltipTrigger,
  TooltipContent,
  TooltipProvider,
} from "@gunjo/ui"
import {
  IconCalendarPlus,
  IconChevronRight,
  IconClock,
  IconUsers,
  IconAlertTriangle,
  IconChecklist,
  IconCalendarRepeat,
} from "@tabler/icons-react"
import {
  PAIRS,
  type Pair,
  CADENCE_LABEL,
  CADENCE_DAYS,
  TODAY,
  daysBetween,
  isOverdue,
  overdueRatio,
  openActions,
  latestMood,
  isThisWeek,
  formatJpDate,
} from "./data"
import { MoodBadge, OverdueBadge } from "./ui"
import { PairDetailSheet } from "./PairDetailSheet"

type FilterKey = "all" | "overdue" | "thisweek"

function SummaryMetrics() {
  const totalPairs = PAIRS.length
  const thisWeek = PAIRS.filter((p) => isThisWeek(p.nextDate)).length
  const overdue = PAIRS.filter(isOverdue).length
  const avgCycle = Math.round(
    PAIRS.reduce((s, p) => s + CADENCE_DAYS[p.cadence], 0) / PAIRS.length
  )
  const openA = PAIRS.reduce((s, p) => s + openActions(p).length, 0)

  return (
    <section aria-label="サマリー指標" className="grid grid-cols-2 gap-3 sm:grid-cols-3 lg:grid-cols-5">
      <Statistic label="対象ペア" value={`${totalPairs}組`} hint="アクティブな1on1関係" />
      <Statistic label="今週実施予定" value={`${thisWeek}件`} trend="flat" hint="今後7日間" />
      <Statistic
        label="未実施（期限超過）"
        value={`${overdue}組`}
        trend={overdue > 0 ? "up" : "flat"}
        tone={overdue > 0 ? "negative" : "neutral"}
        hint="サイクル超過・次回未設定"
      />
      <Statistic label="平均サイクル" value={`${avgCycle}日`} hint="隔週/月次の平均" />
      <Statistic
        label="オープンなアクション"
        value={`${openA}件`}
        trend="flat"
        hint="未完了のネクストアクション"
      />
    </section>
  )
}

function UpcomingThisWeek({ onOpen }: { onOpen: (p: Pair) => void }) {
  const upcoming = PAIRS.filter((p) => isThisWeek(p.nextDate)).sort((a, b) =>
    (a.nextDate ?? "").localeCompare(b.nextDate ?? "")
  )
  return (
    <Card>
      <CardHeader className="p-4 pb-2">
        <CardTitle as="h2" className="flex items-center gap-2 text-base">
          <IconClock className="h-4 w-4 text-muted-foreground" aria-hidden />
          今週の予定
        </CardTitle>
        <CardDescription>今後7日以内に予定されている1on1</CardDescription>
      </CardHeader>
      <CardContent className="p-4 pt-2">
        {upcoming.length === 0 ? (
          <EmptyState title="今週の予定はありません" headingLevel={3} className="py-6" />
        ) : (
          <ul className="divide-y divide-border" role="list">
            {upcoming.map((p) => (
              <li key={p.id}>
                <button
                  type="button"
                  onClick={() => onOpen(p)}
                  className="flex w-full items-center gap-3 py-2.5 text-left transition-colors hover:bg-muted/40 focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring rounded-md"
                >
                  <div className="flex w-16 shrink-0 flex-col items-center rounded-md border border-border bg-muted/40 px-1 py-1.5">
                    <span className="text-[11px] text-muted-foreground">
                      {p.nextDate ? formatJpDate(p.nextDate).slice(0, formatJpDate(p.nextDate).indexOf("(")) : ""}
                    </span>
                    <span className="text-sm font-semibold tabular-nums text-foreground">{p.nextTime}</span>
                  </div>
                  <PersonCell
                    name={p.report.name}
                    secondary={`${p.report.role} · 上司 ${p.manager.name}`}
                    size="sm"
                    className="min-w-0 flex-1"
                  />
                  <IconChevronRight className="h-4 w-4 shrink-0 text-muted-foreground" aria-hidden />
                </button>
              </li>
            ))}
          </ul>
        )}
      </CardContent>
    </Card>
  )
}

function HealthMeter({ pair }: { pair: Pair }) {
  const ratio = overdueRatio(pair)
  const overdue = isOverdue(pair)
  const elapsed = daysBetween(pair.lastDate, TODAY)
  const window = CADENCE_DAYS[pair.cadence]
  return (
    <Meter
      value={Math.min(elapsed, window * 1.5)}
      max={window}
      direction="higher-is-worse"
      size="inline"
      tone={overdue ? "destructive" : ratio > 0.8 ? "warning" : "success"}
      label={`実施サイクル: 前回から${elapsed}日 / ${window}日`}
      formatValue={() => `${elapsed}日`}
    />
  )
}

function PairRow({ pair, onOpen }: { pair: Pair; onOpen: (p: Pair) => void }) {
  const overdue = isOverdue(pair)
  const openCount = openActions(pair).length
  const elapsed = daysBetween(pair.lastDate, TODAY)

  return (
    <li>
      <button
        type="button"
        onClick={() => onOpen(pair)}
        aria-label={`${pair.report.name}と${pair.manager.name}の1on1詳細を開く`}
        className="grid w-full grid-cols-1 items-center gap-3 rounded-lg border border-border bg-card p-3 text-left transition-colors hover:border-foreground/20 hover:bg-muted/30 focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring sm:grid-cols-[1.4fr_1.4fr_auto] sm:gap-4"
      >
        {/* report */}
        <PersonCell
          name={pair.report.name}
          secondary={`${pair.report.dept}`}
          tertiary={pair.report.role}
          size="md"
          trailing={<MoodBadge mood={latestMood(pair)} />}
        />
        {/* manager (the pair's other half) */}
        <div className="flex items-center gap-2 border-t border-border pt-3 sm:border-0 sm:border-l sm:pl-4 sm:pt-0">
          <span className="text-[11px] font-medium text-muted-foreground sm:hidden">上司</span>
          <PersonCell
            name={pair.manager.name}
            secondary={pair.manager.role}
            size="sm"
            className="min-w-0 flex-1"
          />
        </div>
        {/* signals */}
        <div className="flex flex-col gap-2 border-t border-border pt-3 sm:w-64 sm:border-0 sm:border-l sm:pl-4 sm:pt-0">
          <div className="flex items-center justify-between gap-2">
            <Badge variant="outline">{CADENCE_LABEL[pair.cadence]}</Badge>
            {overdue ? (
              <OverdueBadge />
            ) : pair.nextDate ? (
              <Tag variant="outline" size="sm">
                次回 {formatJpDate(pair.nextDate).replace("日", "日").split("(")[0]}
              </Tag>
            ) : (
              <Tag variant="destructive" size="sm">
                次回未設定
              </Tag>
            )}
          </div>
          <HealthMeter pair={pair} />
          <div className="flex items-center justify-between text-xs text-muted-foreground">
            <span>前回 {formatJpDate(pair.lastDate).split("(")[0]} · {elapsed}日前</span>
            {openCount > 0 ? (
              <span className="inline-flex items-center gap-1 font-medium text-foreground">
                <IconChecklist className="h-3.5 w-3.5" aria-hidden />
                アクション{openCount}
              </span>
            ) : (
              <span className="text-success">アクション完了</span>
            )}
          </div>
        </div>
      </button>
    </li>
  )
}

export default function OneOnOnePage() {
  const [filter, setFilter] = React.useState<FilterKey>("all")
  const [selected, setSelected] = React.useState<Pair | null>(null)
  const [open, setOpen] = React.useState(false)

  const onOpen = React.useCallback((p: Pair) => {
    setSelected(p)
    setOpen(true)
  }, [])

  const filtered = React.useMemo(() => {
    const list =
      filter === "overdue"
        ? PAIRS.filter(isOverdue)
        : filter === "thisweek"
        ? PAIRS.filter((p) => isThisWeek(p.nextDate))
        : PAIRS
    // overdue first, then soonest gap
    return [...list].sort((a, b) => {
      if (isOverdue(a) !== isOverdue(b)) return isOverdue(a) ? -1 : 1
      return overdueRatio(b) - overdueRatio(a)
    })
  }, [filter])

  const overdueCount = PAIRS.filter(isOverdue).length

  return (
    <TooltipProvider>
      <main className="mx-auto w-full max-w-6xl px-4 py-6 sm:px-6 sm:py-8">
        {/* Header */}
        <header className="mb-6 flex flex-col gap-3 sm:flex-row sm:items-start sm:justify-between">
          <div>
            <div className="flex items-center gap-2">
              <span className="inline-flex h-9 w-9 items-center justify-center rounded-lg bg-primary/10 text-primary">
                <IconUsers className="h-5 w-5" aria-hidden />
              </span>
              <h1 className="text-xl font-bold tracking-tight text-foreground">1on1 管理</h1>
            </div>
            <p className="mt-1 text-sm text-muted-foreground">
              マネージャーとメンバーの定期1on1。継続性・コンディション・ネクストアクションを一覧で。
            </p>
          </div>
          <div className="flex items-center gap-2">
            {overdueCount > 0 ? (
              <Tooltip>
                <TooltipTrigger asChild>
                  <Badge variant="destructive" icon={<IconAlertTriangle />}>
                    要対応 {overdueCount}
                  </Badge>
                </TooltipTrigger>
                <TooltipContent>サイクルを超過、または次回未設定のペア</TooltipContent>
              </Tooltip>
            ) : null}
            <Button size="sm" variant="default">
              <IconCalendarPlus className="h-4 w-4" aria-hidden />
              1on1を予定
            </Button>
          </div>
        </header>

        <SummaryMetrics />

        <div className="mt-6 grid grid-cols-1 gap-6 lg:grid-cols-[1fr_320px]">
          {/* Pair list */}
          <section aria-label="1on1ペア一覧" className="order-2 lg:order-1">
            <div className="mb-3 flex items-center justify-between gap-3">
              <h2 className="flex items-center gap-2 text-base font-semibold text-foreground">
                <IconCalendarRepeat className="h-4 w-4 text-muted-foreground" aria-hidden />
                ペア一覧
                <span className="text-sm font-normal text-muted-foreground">（{filtered.length}）</span>
              </h2>
              <div className="w-40">
                <Select
                  aria-label="ペアの絞り込み"
                  value={filter}
                  onChange={(e) => setFilter(e.target.value as FilterKey)}
                >
                  <option value="all">すべて</option>
                  <option value="overdue">期限超過のみ</option>
                  <option value="thisweek">今週予定のみ</option>
                </Select>
              </div>
            </div>
            {filtered.length === 0 ? (
              <EmptyState
                title="該当するペアはありません"
                description="絞り込み条件を変更してください。"
                headingLevel={3}
              />
            ) : (
              <ul className="flex flex-col gap-3" role="list">
                {filtered.map((p) => (
                  <PairRow key={p.id} pair={p} onOpen={onOpen} />
                ))}
              </ul>
            )}
          </section>

          {/* Right rail */}
          <aside className="order-1 flex flex-col gap-6 lg:order-2">
            <UpcomingThisWeek onOpen={onOpen} />
            <Card>
              <CardHeader className="p-4 pb-2">
                <CardTitle as="h2" className="text-base">
                  ヒント
                </CardTitle>
              </CardHeader>
              <CardContent className="p-4 pt-2 text-sm text-muted-foreground">
                <p>
                  サイクルを超過、もしくは次回が未設定のペアは
                  <span className="mx-1 align-middle">
                    <OverdueBadge />
                  </span>
                  で表示されます。早めに予定を入れましょう。
                </p>
                <Separator className="my-3" />
                <p>各行をタップすると、履歴・アクション・コンディション推移を確認できます。</p>
              </CardContent>
            </Card>
          </aside>
        </div>

        <PairDetailSheet pair={selected} open={open} onOpenChange={setOpen} />
      </main>
    </TooltipProvider>
  )
}

// Domain data for the 1on1 / フィードバック管理画面.
// Realistic Japanese HR-tech content — managers, reports, real talking points.

export type Cadence = "biweekly" | "monthly"
export type ActionStatus = "open" | "in_progress" | "done"
/** 1=とても良い … 5=しんどい (low = good, high = struggling) — but we store 1..5 where 5 is best to chart "up = good". */
export type Mood = 1 | 2 | 3 | 4 | 5

export interface Person {
  id: string
  name: string
  kana: string
  dept: string
  role: string
  avatar?: string
}

export interface ActionItem {
  id: string
  title: string
  owner: "manager" | "report"
  due: string // ISO date
  status: ActionStatus
}

export interface Meeting {
  id: string
  date: string // ISO date
  durationMin: number
  agenda: string[]
  reportNotes: string // 本人の話したこと
  managerNotes: string // 上司の所感
  mood: Mood
  actions: ActionItem[]
}

export interface Pair {
  id: string
  manager: Person
  report: Person
  cadence: Cadence
  lastDate: string // ISO of most recent done 1on1
  nextDate: string | null // ISO of next scheduled, null if unscheduled
  nextTime?: string // HH:mm
  meetings: Meeting[] // newest first
}

export const CADENCE_LABEL: Record<Cadence, string> = {
  biweekly: "隔週",
  monthly: "月次",
}

export const CADENCE_DAYS: Record<Cadence, number> = {
  biweekly: 14,
  monthly: 30,
}

export const ACTION_STATUS_LABEL: Record<ActionStatus, string> = {
  open: "未着手",
  in_progress: "進行中",
  done: "完了",
}

export const MOOD_LABEL: Record<Mood, string> = {
  5: "とても良い",
  4: "良い",
  3: "ふつう",
  2: "やや低い",
  1: "しんどい",
}

