// ---- Derived helpers -------------------------------------------------------

export function daysBetween(aIso: string, bIso: string): number {
  const a = new Date(aIso + "T00:00:00")
  const b = new Date(bIso + "T00:00:00")
  return Math.round((b.getTime() - a.getTime()) / 86_400_000)
}

/** Whether a pair is overdue: no future date scheduled AND the gap since last
 *  exceeds its cadence window (with a small grace). */
export function isOverdue(pair: Pair): boolean {
  if (pair.nextDate && pair.nextDate >= TODAY) return false
  const gap = daysBetween(pair.lastDate, TODAY)
  return gap > CADENCE_DAYS[pair.cadence]
}

/** 0..1 health: how much of the cadence window has elapsed since last 1on1.
 *  Higher = closer to / past due. */
export function overdueRatio(pair: Pair): number {
  const gap = daysBetween(pair.lastDate, TODAY)
  return gap / CADENCE_DAYS[pair.cadence]
}

export function openActions(pair: Pair): ActionItem[] {
  return pair.meetings.flatMap((m) => m.actions).filter((a) => a.status !== "done")
}

export function moodTrend(pair: Pair): number[] {
  // oldest → newest for the sparkline
  return [...pair.meetings].reverse().map((m) => m.mood)
}

export function latestMood(pair: Pair): Mood {
  return pair.meetings[0]?.mood ?? 3
}

export function isThisWeek(iso: string | null): boolean {
  if (!iso) return false
  const d = daysBetween(TODAY, iso)
  return d >= 0 && d <= 7
}

export function formatJpDate(iso: string): string {
  const d = new Date(iso + "T00:00:00")
  const w = ["日", "月", "火", "水", "木", "金", "土"][d.getDay()]
  return `${d.getMonth() + 1}月${d.getDate()}日(${w})`
}

export function formatShortDate(iso: string): string {
  const d = new Date(iso + "T00:00:00")
  return `${d.getMonth() + 1}/${d.getDate()}`
}

"use client"

import * as React from "react"
import { Badge } from "@gunjo/ui"
import { IconAlertTriangle, IconMoodSmile, IconMoodNeutral, IconMoodSad } from "@tabler/icons-react"
import { type Mood, MOOD_LABEL } from "./data"

/** Mood pill with an icon, so it never relies on colour alone. */
export function MoodBadge({ mood }: { mood: Mood }) {
  const variant = mood >= 4 ? "success" : mood <= 2 ? "destructive" : "warning"
  const Icon = mood >= 4 ? IconMoodSmile : mood <= 2 ? IconMoodSad : IconMoodNeutral
  return (
    <Badge variant={variant} icon={<Icon />}>
      {MOOD_LABEL[mood]}
    </Badge>
  )
}

export function OverdueBadge() {
  return (
    <Badge variant="destructive" icon={<IconAlertTriangle />}>
      期限超過
    </Badge>
  )
}
